package com.securestack;import org.junit.jupiter.api.Test;import static org.junit.jupiter.api.Assertions.*;import java.util.*;import com.securestack.analysis.ai.Ai.MockAiAnalysisProvider;import com.securestack.model.Entities.Finding;import com.securestack.model.Enums.*;class ScanServiceTest{@Test void mockAiSummarizes(){var r=new MockAiAnalysisProvider().generateSummary(new com.securestack.analysis.ai.Ai.AiAnalysisRequest("x",80,Map.of(Severity.HIGH,1L),Map.of(Category.SECRETS,1L),"STANDARD"));assertTrue(r.executiveSummary().contains("80"));}@Test void riskMath(){Finding f=new Finding();f.severity=Severity.CRITICAL;Finding h=new Finding();h.severity=Severity.HIGH;var svc=new com.securestack.service.ScanService(List.of(),null,null,new MockAiAnalysisProvider());assertEquals(70,svc.score(List.of(f,h)));assertEquals(RiskLevel.MODERATE,svc.level(70));}}
